def gen(rng, size):
    n = max(1, min(size, 100))
    matrix = [[0] * n for _ in range(n)]
    for i in range(n):
        for j in range(i + 1, n):
            v = rng.randint(0, 1)
            matrix[i][j] = v
            matrix[j][i] = v
    return [matrix]

